"use strict";(self.webpackChunkastrology_garden=self.webpackChunkastrology_garden||[]).push([["4058"],{5604(e,n,i){i.r(n),i.d(n,{metadata:()=>o,default:()=>p,frontMatter:()=>r,contentTitle:()=>t,toc:()=>l,assets:()=>c});var o=JSON.parse('{"id":"Planets & Points/Venus","title":"Venus","description":"Principle:","source":"@site/docs/Planets & Points/Venus.md","sourceDirName":"Planets & Points","slug":"/Planets & Points/Venus","permalink":"/Planets & Points/Venus","draft":false,"unlisted":false,"editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/docs/Planets & Points/Venus.md","tags":[],"version":"current","frontMatter":{},"sidebar":"tutorialSidebar","previous":{"title":"Uranus","permalink":"/Planets & Points/Uranus"},"next":{"title":"mercury","permalink":"/Planets & Points/mercury"}}'),a=i(4848),s=i(8453);let r={},t,c={},l=[{value:"T\u0142umaczenie na j\u0119zyk polski (Translation)",id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",level:3}];function d(e){let n={h3:"h3",li:"li",p:"p",ul:"ul",...(0,s.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(n.p,{children:"Principle:"}),"\n",(0,a.jsx)(n.p,{children:"Love, art."}),"\n",(0,a.jsx)(n.p,{children:"Psychological Correspondence:"}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Physical attraction, feeling, a sense of harmony, beauty and art, a positive outlook or attitude towards life."}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Sexual aberration, sentimentality, a want of taste, heedlessness, vice."}),"\n"]}),"\n"]}),"\n",(0,a.jsx)(n.p,{children:"Biological Correspondence:"}),"\n",(0,a.jsx)(n.p,{children:"Glandular products (Kidneys, veins)"}),"\n",(0,a.jsx)(n.p,{children:"Sociological Correspondence:"}),"\n",(0,a.jsx)(n.p,{children:"A young girl or maiden, sweetheart or mistress, people who are connected with centres of art or centres of entertainment."}),"\n",(0,a.jsx)(n.p,{children:"Positions in Houses and Signs:"}),"\n",(0,a.jsx)(n.p,{children:"I. Ardent and passionate love, the power to wish, revelling or romantic dreaming, the development of creative powers. \u2013 The desire for change, the tendency to involve oneself in love-adventures, love at first sight."}),"\n",(0,a.jsx)(n.p,{children:"II. A deep-seated feeling, strong personal power of attraction, constancy, faithfulness, a conservative character. Love of luxury and of precious stones, artistic interests."}),"\n",(0,a.jsx)(n.p,{children:"III. All-embracing sympathy, charm, courtesy, a cooperative attitude towards others, the ability to accommodate oneself to circumstances, the desire to discuss ideas with others. \u2013 Superficial love-attachments lead to conflicts."}),"\n",(0,a.jsx)(n.p,{children:"IV. A deep-seated feeling of love, a strong urge to lean on somebody, the appreciation of family and home, art and music. \u2013 Digestive troubles are caused by excessive enjoyment of delicacies or tidbits."}),"\n",(0,a.jsx)(n.p,{children:"V. A warm heart desiring love and also arousing love easily in the partner. Abundance of love. Enjoyment of social entertainment, pleasure and games. The desire to dress well and to live in an environment of luxury. \u2013 Quick contacts with other people, often a premature marriage."}),"\n",(0,a.jsx)(n.p,{children:"VI. A moral sense, the dictates of the heart are often suppressed by practical considerations, indecision in matters of love, the striving for moral purity."}),"\n",(0,a.jsx)(n.p,{children:"VII. A person who knows how to live, a friendly and obliging manner brings about contacts with other people quickly, the enjoyment of social engagements and pleasures, good taste, artistic skill. \u2013 The danger of scattering one's affections."}),"\n",(0,a.jsx)(n.p,{children:"VIII. Strong powers of attraction, a passionate disposition, vacillation or wavering between the extremes of self-control and licentiousness, fanaticism in love, jealousy, the tendency to waste one's vital energy. \u2013 The danger of illness from intemperance."}),"\n",(0,a.jsx)(n.p,{children:"IX. The power to wish, idealistic motives in love-life, the inclination to romantic imaginings, occasional moodiness, hypersensitiveness, instability, the scattering of one's energies."}),"\n",(0,a.jsx)(n.p,{children:'X. Constancy, faithfulness, a sense of responsibility, self-control in love-relationship, an attachment to mature partners who have gained experience in life. Jealousy, distrust, obsolete views. Too much self-control and a "matter of fact" manner may bring about the danger of disappointments and separations.'}),"\n",(0,a.jsx)(n.p,{children:"XI. Modern and progressive views on love-relationship, peculiar plans and ideas, the enjoyment of social contacts, a love of independence, an appreciation of modern art-forms. \u2013 Associations through friendship are important. Protection (in the sense of benefits through sponsorship)."}),"\n",(0,a.jsx)(n.p,{children:"XII. A longing for love, subjection to emotional and sexual life, an occasional lack of self-control, impressionability, seducibility, a care-free nature, comfort, a predominating love of music and of other artistic activities of an enjoyable nature."}),"\n",(0,a.jsx)(n.h3,{id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",children:"T\u0142umaczenie na j\u0119zyk polski (Translation)"}),"\n",(0,a.jsx)(n.p,{children:"WENUS"}),"\n",(0,a.jsx)(n.p,{children:"Zasada:"}),"\n",(0,a.jsx)(n.p,{children:"Mi\u0142o\u015B\u0107, sztuka."}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja psychologiczna:"}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Atrakcyjno\u015B\u0107 fizyczna, uczucie, zmys\u0142 harmonii, pi\u0119kna i sztuki, pozytywne spojrzenie lub nastawienie do \u017Cycia."}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Aberracja seksualna, sentymentalizm, brak gustu, nieostro\u017Cno\u015B\u0107 (beztroska), wyst\u0119pek."}),"\n"]}),"\n"]}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja biologiczna:"}),"\n",(0,a.jsx)(n.p,{children:"Produkty gruczo\u0142owe (nerki, \u017Cy\u0142y)"}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja socjologiczna:"}),"\n",(0,a.jsx)(n.p,{children:"M\u0142oda dziewczyna lub panna, ukochana lub kochanka, ludzie powi\u0105zani z centrami sztuki lub centrami rozrywki."}),"\n",(0,a.jsx)(n.p,{children:"Pozycje w domach i znakach:"}),"\n",(0,a.jsx)(n.p,{children:"I. \u017Barliwa i nami\u0119tna mi\u0142o\u015B\u0107, si\u0142a pragnienia, biesiadowanie lub romantyczne marzenia, rozw\xf3j si\u0142 tw\xf3rczych. \u2013 Pragnienie zmian, tendencja do anga\u017Cowania si\u0119 w przygody mi\u0142osne, mi\u0142o\u015B\u0107 od pierwszego wejrzenia."}),"\n",(0,a.jsx)(n.p,{children:"II. G\u0142\u0119boko zakorzenione uczucie, silna osobista si\u0142a przyci\u0105gania, sta\u0142o\u015B\u0107, wierno\u015B\u0107, konserwatywny charakter. Zami\u0142owanie do luksusu i szlachetnych kamieni, zainteresowania artystyczne."}),"\n",(0,a.jsx)(n.p,{children:"III. Wszechogarniaj\u0105ca sympatia, urok, uprzejmo\u015B\u0107, kooperatywna postawa wobec innych, zdolno\u015B\u0107 do przystosowania si\u0119 do okoliczno\u015Bci, pragnienie dyskutowania o pomys\u0142ach z innymi. \u2013 Powierzchowne przywi\u0105zania mi\u0142osne prowadz\u0105 do konflikt\xf3w."}),"\n",(0,a.jsx)(n.p,{children:"IV. G\u0142\u0119boko zakorzenione uczucie mi\u0142o\u015Bci, silna potrzeba oparcia si\u0119 na kim\u015B, docenianie rodziny i domu, sztuki i muzyki. \u2013 Problemy z trawieniem s\u0105 powodowane przez nadmierne raczenie si\u0119 przysmakami lub smako\u0142ykami."}),"\n",(0,a.jsx)(n.p,{children:"V. Ciep\u0142e serce pragn\u0105ce mi\u0142o\u015Bci i \u0142atwo wzbudzaj\u0105ce mi\u0142o\u015B\u0107 u partnera. Obfito\u015B\u0107 mi\u0142o\u015Bci. Czerpanie rado\u015Bci z towarzyskich rozrywek, przyjemno\u015Bci i gier. Pragnienie dobrego ubierania si\u0119 i \u017Cycia w luksusowym otoczeniu. \u2013 Szybkie kontakty z innymi lud\u017Ami, cz\u0119sto przedwczesne ma\u0142\u017Ce\u0144stwo."}),"\n",(0,a.jsx)(n.p,{children:"VI. Zmys\u0142 moralny, nakazy serca s\u0105 cz\u0119sto t\u0142umione przez wzgl\u0119dy praktyczne, niezdecydowanie w sprawach mi\u0142osnych, d\u0105\u017Cenie do czysto\u015Bci moralnej."}),"\n",(0,a.jsx)(n.p,{children:"VII. Osoba, kt\xf3ra wie, jak \u017Cy\u0107, przyjazny i us\u0142u\u017Cny spos\xf3b bycia przynosi szybkie kontakty z innymi lud\u017Ami, czerpanie rado\u015Bci z towarzyskich spotka\u0144 i przyjemno\u015Bci, dobry gust, umiej\u0119tno\u015Bci artystyczne. \u2013 Niebezpiecze\u0144stwo rozproszenia swoich uczu\u0107."}),"\n",(0,a.jsx)(n.p,{children:"VIII. Silne moce przyci\u0105gania, nami\u0119tne usposobienie, chwiejno\u015B\u0107 lub wahanie mi\u0119dzy skrajno\u015Bciami samokontroli a rozpust\u0105, fanatyzm w mi\u0142o\u015Bci, zazdro\u015B\u0107, tendencja do marnowania swojej energii \u017Cyciowej. \u2013 Niebezpiecze\u0144stwo choroby z powodu nietrze\u017Awo\u015Bci (nieumiarkowania)."}),"\n",(0,a.jsx)(n.p,{children:"IX. Si\u0142a pragnienia, idealistyczne motywy w \u017Cyciu mi\u0142osnym, sk\u0142onno\u015B\u0107 do romantycznych wyobra\u017Ce\u0144, okazjonalna humorzasto\u015B\u0107, nadwra\u017Cliwo\u015B\u0107, niestabilno\u015B\u0107, rozpraszanie swoich energii."}),"\n",(0,a.jsx)(n.p,{children:"X. Sta\u0142o\u015B\u0107, wierno\u015B\u0107, poczucie odpowiedzialno\u015Bci, samokontrola w relacji mi\u0142osnej, przywi\u0105zanie do dojrza\u0142ych partner\xf3w, kt\xf3rzy zebrali do\u015Bwiadczenie \u017Cyciowe. Zazdro\u015B\u0107, nieufno\u015B\u0107, przestarza\u0142e pogl\u0105dy. Zbyt du\u017Ca samokontrola i \u201Erzeczowy\u201D spos\xf3b bycia mog\u0105 przynie\u015B\u0107 niebezpiecze\u0144stwo rozczarowa\u0144 i rozsta\u0144."}),"\n",(0,a.jsx)(n.p,{children:"XI. Nowoczesne i post\u0119powe pogl\u0105dy na relacje mi\u0142osne, osobliwe plany i pomys\u0142y, czerpanie rado\u015Bci z kontakt\xf3w towarzyskich, zami\u0142owanie do niezale\u017Cno\u015Bci, docenianie nowoczesnych form sztuki. \u2013 Zwi\u0105zki poprzez przyja\u017A\u0144 s\u0105 wa\u017Cne. Ochrona (w sensie korzy\u015Bci p\u0142yn\u0105cych ze sponsoringu/protektoratu)."}),"\n",(0,a.jsx)(n.p,{children:"XII. T\u0119sknota za mi\u0142o\u015Bci\u0105, podporz\u0105dkowanie \u017Cyciu emocjonalnemu i seksualnemu, okazjonalny brak samokontroli, podatno\u015B\u0107 na wra\u017Cenia, podatno\u015B\u0107 na uwodzenie, beztroska natura, wygoda, dominuj\u0105ce zami\u0142owanie do muzyki i innych dzia\u0142a\u0144 artystycznych o charakterze rozrywkowym."})]})}function p(e={}){let{wrapper:n}={...(0,s.R)(),...e.components};return n?(0,a.jsx)(n,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},8453(e,n,i){i.d(n,{R:()=>r,x:()=>t});var o=i(6540);let a={},s=o.createContext(a);function r(e){let n=o.useContext(s);return o.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function t(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:r(e.components),o.createElement(s.Provider,{value:n},e.children)}}}]);